Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` that talks to it — no real port, no real server.

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

### Key points

- **`Program`** must be accessible — add `public partial class Program { }` at the bottom of your `Program.cs` if it uses top-level statements.
- **Override services** for isolation (e.g., swap a real DB for an in-memory one):
  ```csharp
  factory.WithWebHostBuilder(builder =>
  {
      builder.ConfigureServices(services =>
      {
          // Replace real dependencies with fakes
      });
  });
  ```
- **SSE transport**: If your server uses the SSE-based Streamable HTTP transport, use `factory.CreateDefaultClient()` and read the SSE stream with `HttpCompletionOption.ResponseHeadersRead`:
  ```csharp
  var req = new HttpRequestMessage(HttpMethod.Post, "/mcp");
  req.Content = JsonContent.Create(rpcPayload);
  var resp = await _client.SendAsync(req, HttpCompletionOption.ResponseHeadersRead);
  using var stream = await resp.Content.ReadAsStreamAsync();
  // parse SSE events from the stream
  ```

Everything runs in-process — fast, deterministic, and no port conflicts in CI.
